svg.script:
(function () {
  'use strict';

  var script = document.currentScript;
  var root = script && script.ownerSVGElement ? script.ownerSVGElement : document.documentElement;
  var q = function (id) { return root.querySelector('#' + id); };
  var route = q('sm-cursor-route');
  var animationMark = q('sm-animation-mark');
  var originalFinal = q('sm-original-final');
  var liquid = q('sm-liquid-reveal');
  var animatedCursor = q('sm-animated-cursor');
  var motion = q('sm-cursor-motion');
  var bobGroup = q('sm-cursor-bob');
  var bankGroup = q('sm-cursor-bank');
  var scaleGroup = q('sm-cursor-scale');
  var shadowLag = q('sm-cursor-shadow-lag');
  var shadowShape = shadowLag.querySelector('use');
  var glow = q('sm-cursor-glow');
  var trail = q('sm-cursor-trail');
  var trailCore = q('sm-cursor-trail-core');
  var prefersReduced = window.matchMedia && window.matchMedia('(prefers-reduced-motion: reduce)').matches;

  var CURSOR_DELAY = 2.18;
  var CURSOR_DURATION = 6.72;
  var LANDING_BLEND = 0.18;
  var routeLength = route.getTotalLength();
  var keyTimes = [0, 0.20, 0.68, 1.18, 1.48, 2.42, 3.49, 4.60, 5.73, 6.24, 6.50, 6.72];
  var keyProgress = [0, 0.012, 0.105, 0.203, 0.235, 0.388, 0.581, 0.775, 0.970, 0.990, 0.997, 1];
  var keyScaleX = [0.50, 0.54, 0.66, 0.68, 0.66, 0.64, 0.72, 0.64, 0.69, 0.82, 1.015, 1];
  var keyScaleY = [0.47, 0.52, 0.62, 0.65, 0.68, 0.70, 0.65, 0.70, 0.66, 0.78, 0.995, 1];
  var keyBank = [-4, -2.5, -1.2, 0, -1.2, -6.2, 2, 6.2, 0.3, 2.8, -0.8, 0];

  var elapsed = 0;
  var lastTimestamp = null;
  var frame = 0;
  var running = false;
  var smoothBank = 0;
  var shadowX = 0;
  var shadowY = 0;

  function clamp(value, min, max) {
    return Math.max(min, Math.min(max, value));
  }

  function smoothstep(value) {
    var t = clamp(value, 0, 1);
    return t * t * (3 - 2 * t);
  }

  function buildMonotone(xs, ys) {
    var n = xs.length;
    var widths = new Array(n - 1);
    var secants = new Array(n - 1);
    var tangents = new Array(n);
    var i;

    for (i = 0; i < n - 1; i += 1) {
      widths[i] = xs[i + 1] - xs[i];
      secants[i] = (ys[i + 1] - ys[i]) / widths[i];
    }

    tangents[0] = secants[0];
    tangents[n - 1] = secants[n - 2];
    for (i = 1; i < n - 1; i += 1) {
      if (secants[i - 1] * secants[i] <= 0) {
        tangents[i] = 0;
      } else {
        var w1 = 2 * widths[i] + widths[i - 1];
        var w2 = widths[i] + 2 * widths[i - 1];
        tangents[i] = (w1 + w2) / (w1 / secants[i - 1] + w2 / secants[i]);
      }
    }

    return function (x) {
      if (x <= xs[0]) return ys[0];
      if (x >= xs[n - 1]) return ys[n - 1];
      var segment = 0;
      while (segment < n - 2 && x > xs[segment + 1]) segment += 1;
      var h = widths[segment];
      var u = (x - xs[segment]) / h;
      var u2 = u * u;
      var u3 = u2 * u;
      var h00 = 2 * u3 - 3 * u2 + 1;
      var h10 = u3 - 2 * u2 + u;
      var h01 = -2 * u3 + 3 * u2;
      var h11 = u3 - u2;
      return h00 * ys[segment] + h10 * h * tangents[segment] +
             h01 * ys[segment + 1] + h11 * h * tangents[segment + 1];
    };
  }

  function sampleSmooth(time, values) {
    if (time <= keyTimes[0]) return values[0];
    if (time >= keyTimes[keyTimes.length - 1]) return values[values.length - 1];
    var segment = 0;
    while (segment < keyTimes.length - 2 && time > keyTimes[segment + 1]) segment += 1;
    var amount = smoothstep((time - keyTimes[segment]) / (keyTimes[segment + 1] - keyTimes[segment]));
    return values[segment] + (values[segment + 1] - values[segment]) * amount;
  }

  function normalizeAngle(angle) {
    while (angle > Math.PI) angle -= Math.PI * 2;
    while (angle < -Math.PI) angle += Math.PI * 2;
    return angle;
  }

  var progressAt = buildMonotone(keyTimes, keyProgress);

  function setOpacity(element, value) {
    element.style.opacity = String(clamp(value, 0, 1));
  }

  function showExactFinal() {
    setOpacity(animationMark, 0);
    setOpacity(originalFinal, 1);
    setOpacity(liquid, 0);
    setOpacity(animatedCursor, 0);
    setOpacity(trail, 0);
    setOpacity(trailCore, 0);
  }

  function render(globalTime, immediate, deltaTime) {
    var local = globalTime - CURSOR_DELAY;
    var liquidFade = smoothstep((globalTime - (CURSOR_DELAY - 0.16)) / 0.14);
    setOpacity(liquid, 1 - liquidFade);

    if (local < 0) {
      setOpacity(animationMark, 1);
      setOpacity(originalFinal, 0);
      setOpacity(animatedCursor, 0);
      setOpacity(trail, 0);
      setOpacity(trailCore, 0);
      return;
    }

    if (local >= CURSOR_DURATION) {
      showExactFinal();
      return;
    }

    var progress = progressAt(local);
    var distance = progress * routeLength;
    var point = route.getPointAtLength(distance);
    var before = route.getPointAtLength(Math.max(0, distance - 1.2));
    var after = route.getPointAtLength(Math.min(routeLength, distance + 1.2));
    var tangentX = after.x - before.x;
    var tangentY = after.y - before.y;
    var tangentLength = Math.max(0.0001, Math.hypot(tangentX, tangentY));
    tangentX /= tangentLength;
    tangentY /= tangentLength;
    var normalX = -tangentY;
    var normalY = tangentX;

    var sampleWindow = 0.015;
    var progressBefore = progressAt(Math.max(0, local - sampleWindow));
    var progressAfter = progressAt(Math.min(CURSOR_DURATION, local + sampleWindow));
    var speed = (progressAfter - progressBefore) * routeLength / (sampleWindow * 2);
    var speedAmount = clamp(speed / 118, 0, 1);

    var incomingAngle = Math.atan2(point.y - before.y, point.x - before.x);
    var outgoingAngle = Math.atan2(after.y - point.y, after.x - point.x);
    var curvatureBank = clamp(normalizeAngle(outgoingAngle - incomingAngle) * 180 / Math.PI * 1.8, -5.5, 5.5);
    var authoredBank = sampleSmooth(local, keyBank);
    var targetBank = clamp(authoredBank * 0.68 + curvatureBank * 0.32, -6.5, 6.5);
    var alpha = immediate ? 1 : 1 - Math.exp(-Math.max(0.001, deltaTime) / 0.13);
    smoothBank += (targetBank - smoothBank) * alpha;

    var bobIn = smoothstep((local - 0.18) / 0.52);
    var bobOut = 1 - smoothstep((local - 5.72) / 0.72);
    var bob = (
      Math.sin(progress * Math.PI * 4) * 0.72 +
      Math.sin(progress * Math.PI * 8 + 0.7) * 0.12
    ) * bobIn * bobOut;
    var x = point.x + normalX * bob;
    var y = point.y + normalY * bob;

    var scaleX = sampleSmooth(local, keyScaleX);
    var scaleY = sampleSmooth(local, keyScaleY);
    var landingBlend = smoothstep((local - (CURSOR_DURATION - LANDING_BLEND)) / LANDING_BLEND);
    var entranceOpacity = smoothstep(local / 0.22);
    var animatedOpacity = entranceOpacity * (1 - landingBlend);

    motion.setAttribute('transform', 'translate(' + x.toFixed(3) + ' ' + y.toFixed(3) + ')');
    bobGroup.setAttribute('transform', 'translate(0 0)');
    bankGroup.setAttribute('transform', 'rotate(' + smoothBank.toFixed(3) + ')');
    scaleGroup.setAttribute('transform', 'scale(' + scaleX.toFixed(4) + ' ' + scaleY.toFixed(4) + ')');

    var lag = 0.55 + speedAmount * 1.55;
    var targetShadowX = -tangentX * lag;
    var targetShadowY = -tangentY * lag + 0.65;
    shadowX += (targetShadowX - shadowX) * alpha;
    shadowY += (targetShadowY - shadowY) * alpha;
    shadowLag.setAttribute('transform', 'translate(' + shadowX.toFixed(3) + ' ' + shadowY.toFixed(3) + ')');

    var centerBreath = Math.exp(-Math.pow((local - 1.10) / 0.17, 2));
    setOpacity(shadowShape, (0.14 + speedAmount * 0.20) * (1 - landingBlend));
    setOpacity(glow, (0.09 + speedAmount * 0.15 + centerBreath * 0.22) * (1 - landingBlend));
    setOpacity(animatedCursor, animatedOpacity);
    setOpacity(animationMark, 1 - landingBlend);
    setOpacity(originalFinal, landingBlend);

    var trailEnvelope = smoothstep(local / 0.22) * (1 - landingBlend);
    trail.setAttribute('stroke-dasharray', '42 ' + (routeLength + 42).toFixed(2));
    trail.setAttribute('stroke-dashoffset', (42 - distance).toFixed(2));
    trailCore.setAttribute('stroke-dasharray', '22 ' + (routeLength + 22).toFixed(2));
    trailCore.setAttribute('stroke-dashoffset', (22 - distance).toFixed(2));
    setOpacity(trail, (0.14 + speedAmount * 0.23) * trailEnvelope);
    setOpacity(trailCore, (0.10 + speedAmount * 0.16) * trailEnvelope);
  }

  function tick(timestamp) {
    if (!running) return;
    if (lastTimestamp === null) lastTimestamp = timestamp;
    var deltaTime = clamp((timestamp - lastTimestamp) / 1000, 0, 0.05);
    lastTimestamp = timestamp;
    elapsed += deltaTime;
    render(elapsed, false, deltaTime);
    frame = window.requestAnimationFrame(tick);
  }

  function pause() {
    if (!running) return;
    running = false;
    window.cancelAnimationFrame(frame);
    lastTimestamp = null;
    if (root.pauseAnimations) root.pauseAnimations();
  }

  function resume() {
    if (prefersReduced || running) return;
    running = true;
    lastTimestamp = null;
    if (root.unpauseAnimations) root.unpauseAnimations();
    frame = window.requestAnimationFrame(tick);
  }

  function replay() {
    if (prefersReduced) return;
    elapsed = 0;
    smoothBank = 0;
    shadowX = 0;
    shadowY = 0;
    if (root.setCurrentTime) root.setCurrentTime(0);
    render(0, true, 0.016);
    resume();
  }

  function seek(seconds) {
    if (prefersReduced) return;
    pause();
    elapsed = Math.max(0, Number(seconds) || 0);
    if (root.setCurrentTime) root.setCurrentTime(elapsed);
    render(elapsed, true, 0.016);
  }

  root.__smReplay = replay;
  root.__smPause = pause;
  root.__smResume = resume;
  root.__smSeek = seek;

  if (prefersReduced) {
    if (animationMark) animationMark.style.display = 'none';
    if (liquid) liquid.style.display = 'none';
    showExactFinal();
  } else {
    render(0, true, 0.016);
    resume();
  }

  document.addEventListener('visibilitychange', function () {
    if (document.hidden) pause();
    else resume();
  });
}());
